design.css:
/* IQRA Sacred Design System — Generated locally */
:root {
  --iqra-gold:      #C9A84C;
  --iqra-emerald:   #2D6A4F;
  --iqra-ink:       #1A1A2E;
  --iqra-light:     #FAFAFA;
  --iqra-parchment: #F5F0E8;
  --iqra-accent:    #8B5CF6;

  --font-arabic:  "Amiri", "Scheherazade New", serif;
  --font-latin:   "Inter", "Segoe UI", sans-serif;
  --font-mono:    "JetBrains Mono", "Fira Code", monospace;

  --radius-sm:  3px;
  --radius-md:  7px;
  --radius-lg:  14px;
  --radius-xl:  19px;

  --space-xs:   7px;
  --space-sm:   14px;
  --space-md:   28px;
  --space-lg:   56px;
}

.iqra-card {
  background: var(--iqra-ink);
  border: 1px solid var(--iqra-gold);
  border-radius: var(--radius-xl);
  padding: var(--space-md);
  color: var(--iqra-light);
  font-family: var(--font-latin);
}

.iqra-card[dir="rtl"] {
  font-family: var(--font-arabic);
}

.iqra-ayah {
  font-family: var(--font-arabic);
  font-size: 1.4rem;
  color: var(--iqra-gold);
  text-align: center;
  line-height: 2;
  padding: var(--space-sm);
  border-bottom: 1px solid rgba(201, 168, 76, 0.3);
  margin-bottom: var(--space-sm);
}

.iqra-resonance-badge {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  background: rgba(201, 168, 76, 0.1);
  border: 1px solid var(--iqra-gold);
  border-radius: var(--radius-md);
  padding: 4px var(--space-xs);
  font-size: 0.75rem;
  color: var(--iqra-gold);
}

.iqra-trust-chain {
  font-family: var(--font-mono);
  font-size: 0.7rem;
  color: rgba(255,255,255,0.4);
  border-left: 2px solid var(--iqra-emerald);
  padding-left: var(--space-xs);
  margin-top: var(--space-sm);
}
